/**
 * E2E Test: Performance & Core Web Vitals
 * Verifica tempos de carregamento, tamanhos de recursos e métricas de performance.
 */

import { test, expect } from '@playwright/test';

// -------------------------------------------------------
// Page Load Times
// -------------------------------------------------------
test.describe('Page Load Performance', () => {
  const criticalPages = [
    { path: '/', name: 'Home', maxLoadMs: 8000 },
    { path: '/login', name: 'Login', maxLoadMs: 6000 },
    { path: '/pricing', name: 'Pricing', maxLoadMs: 6000 },
    { path: '/blog', name: 'Blog', maxLoadMs: 6000 },
  ];

  for (const pg of criticalPages) {
    test(`${pg.name} page loads within ${pg.maxLoadMs}ms`, async ({ page }) => {
      const start = Date.now();
      const response = await page.goto(pg.path, { waitUntil: 'domcontentloaded' });
      const loadTime = Date.now() - start;

      expect(response).not.toBeNull();
      expect(response!.status()).toBeLessThan(500);
      // Generous threshold for CI environments
      expect(loadTime).toBeLessThan(pg.maxLoadMs);
    });
  }
});

// -------------------------------------------------------
// Resource Size Checks
// -------------------------------------------------------
test.describe('Resource Sizes', () => {
  test('Home page total transfer size is reasonable', async ({ page }) => {
    let totalBytes = 0;
    const resourceSizes: Array<{ url: string; size: number }> = [];

    page.on('response', async (response) => {
      try {
        const body = await response.body();
        const size = body.length;
        totalBytes += size;
        resourceSizes.push({ url: response.url(), size });
      } catch {
        // Some responses may not have body (e.g., redirects)
      }
    });

    await page.goto('/', { waitUntil: 'load' });

    // Total page weight should be under 10MB (generous threshold)
    const totalMB = totalBytes / (1024 * 1024);
    expect(totalMB).toBeLessThan(10);
  });

  test('No single resource exceeds 3MB', async ({ page }) => {
    const largeResources: Array<{ url: string; sizeMB: number }> = [];

    page.on('response', async (response) => {
      try {
        const body = await response.body();
        const sizeMB = body.length / (1024 * 1024);
        if (sizeMB > 3) {
          largeResources.push({ url: response.url(), sizeMB });
        }
      } catch {
        // Skip responses without body
      }
    });

    await page.goto('/', { waitUntil: 'load' });

    // No single resource should be over 3MB
    expect(largeResources).toHaveLength(0);
  });
});

// -------------------------------------------------------
// JavaScript errors
// -------------------------------------------------------
test.describe('Console Errors', () => {
  test('Home page has no critical console errors', async ({ page }) => {
    const consoleErrors: string[] = [];
    page.on('console', (msg) => {
      if (msg.type() === 'error') {
        consoleErrors.push(msg.text());
      }
    });

    await page.goto('/', { waitUntil: 'domcontentloaded' });
    await page.waitForTimeout(2000);

    // Filter out known acceptable errors (e.g., third-party scripts, analytics)
    const criticalErrors = consoleErrors.filter(
      (err) =>
        !err.includes('favicon') &&
        !err.includes('analytics') &&
        !err.includes('gtag') &&
        !err.includes('hotjar') &&
        !err.includes('intercom') &&
        !err.includes('sentry') &&
        !err.includes('ERR_BLOCKED_BY_CLIENT') && // ad blockers
        !err.includes('net::ERR_') &&
        !err.includes('Failed to load resource')
    );

    // Allow some non-critical errors, but there should be very few
    expect(criticalErrors.length).toBeLessThan(5);
  });

  test('Login page has no critical console errors', async ({ page }) => {
    const consoleErrors: string[] = [];
    page.on('console', (msg) => {
      if (msg.type() === 'error') {
        consoleErrors.push(msg.text());
      }
    });

    await page.goto('/login', { waitUntil: 'domcontentloaded' });
    await page.waitForTimeout(2000);

    const criticalErrors = consoleErrors.filter(
      (err) =>
        !err.includes('favicon') &&
        !err.includes('analytics') &&
        !err.includes('gtag') &&
        !err.includes('hotjar') &&
        !err.includes('sentry') &&
        !err.includes('ERR_BLOCKED_BY_CLIENT') &&
        !err.includes('net::ERR_') &&
        !err.includes('Failed to load resource')
    );

    expect(criticalErrors.length).toBeLessThan(5);
  });
});

// -------------------------------------------------------
// Network Request Failures
// -------------------------------------------------------
test.describe('Network Health', () => {
  test('Home page has no failed critical requests', async ({ page }) => {
    const failedRequests: Array<{ url: string; status: number }> = [];

    page.on('response', (response) => {
      if (response.status() >= 500) {
        failedRequests.push({ url: response.url(), status: response.status() });
      }
    });

    await page.goto('/', { waitUntil: 'load' });

    // No 5xx errors from our own domain
    const ownDomainFailures = failedRequests.filter(
      (r) => r.url.includes('cursostecno') || r.url.includes('localhost')
    );
    expect(ownDomainFailures).toHaveLength(0);
  });

  test('Static assets load correctly', async ({ page }) => {
    const assetErrors: string[] = [];

    page.on('response', (response) => {
      const url = response.url();
      const isAsset =
        url.endsWith('.js') ||
        url.endsWith('.css') ||
        url.endsWith('.woff2') ||
        url.endsWith('.woff');
      if (isAsset && response.status() >= 400) {
        assetErrors.push(`${response.status()} ${url}`);
      }
    });

    await page.goto('/', { waitUntil: 'load' });

    expect(assetErrors).toHaveLength(0);
  });
});

// -------------------------------------------------------
// Lighthouse-style checks (basic)
// -------------------------------------------------------
test.describe('Basic Lighthouse Checks', () => {
  test('Home page has charset and viewport meta', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    const charset = page.locator('meta[charset]');
    await expect(charset).toBeAttached();

    const viewport = page.locator('meta[name="viewport"]');
    await expect(viewport).toBeAttached();
    const viewportContent = await viewport.getAttribute('content');
    expect(viewportContent).toContain('width=device-width');
  });

  test('Critical CSS is loaded (no FOUC)', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    // Check that stylesheets are loaded
    const stylesheets = page.locator('link[rel="stylesheet"], style');
    const count = await stylesheets.count();
    expect(count).toBeGreaterThan(0);
  });

  test('Images use modern formats or proper loading', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    const images = page.locator('img');
    const imgCount = await images.count();

    // Check that images have width/height or loading="lazy"
    let optimizedCount = 0;
    for (let i = 0; i < Math.min(imgCount, 10); i++) {
      const img = images.nth(i);
      const loading = await img.getAttribute('loading');
      const width = await img.getAttribute('width');
      const height = await img.getAttribute('height');
      const hasSize = width && height;
      const isLazy = loading === 'lazy';
      if (hasSize || isLazy) optimizedCount++;
    }

    // At least 50% of images should be optimized (Next.js Image does this automatically)
    if (imgCount > 0) {
      expect(optimizedCount / Math.min(imgCount, 10)).toBeGreaterThanOrEqual(0.3);
    }
  });
});
